<?php declare(strict_types=1);
namespace MOJ\JudicialSystem;
use PDO;
final class Search{public function __construct(private PDO $db=new \PDO('sqlite::memory:')){$this->db=$db->getAttribute(\PDO::ATTR_DRIVER_NAME)==='sqlite'?Database::connect():$db;} public function query(array $p):array{$q=trim((string)($p['q']??''));$where=[];$bind=[];if($q!==''){$where[]='(MATCH(title,summary,full_text,subject) AGAINST (:q IN BOOLEAN MODE) OR decision_number LIKE :like)';$bind['q']=$q;$bind['like']='%'.$q.'%';}foreach(['court_name','city_name','judge_name','subject'] as $f){if(!empty($p[$f])){$where[]="$f = :$f";$bind[$f]=$p[$f];}}$sql='SELECT SQL_CALC_FOUND_ROWS * FROM judicial_decisions '.($where?' WHERE '.implode(' AND ',$where):'').' ORDER BY decision_date DESC, id DESC LIMIT :lim OFFSET :off';$st=$this->db->prepare($sql);foreach($bind as $k=>$v){$st->bindValue(':'.$k,$v);} $st->bindValue(':lim',min(100,max(1,(int)($p['limit']??20))),PDO::PARAM_INT);$st->bindValue(':off',max(0,(int)($p['offset']??0)),PDO::PARAM_INT);$st->execute();return ['items'=>$st->fetchAll(),'total'=>(int)$this->db->query('SELECT FOUND_ROWS()')->fetchColumn()];}}
